css:
/* --- KITTY主题 - v8.0 最终完美版 --- */

/* --- 全局样式 --- */
body {
    background: url('https://i.mji.rip/2025/08/26/695d2b13011410e5590c6dd8eab334b2.jpeg') !important;
    background-size: cover !important;
    background-repeat: no-repeat !important;
    background-attachment: scroll !important; /* ⭐ 性能优化: 解决卡顿问题 */
    background-position: center center !important;
}
.drawer-content {
    background-image: url('https://i.mji.rip/2025/08/26/695d2b13011410e5590c6dd8eab334b2.jpeg') !important;
    background-size: cover !important;
    background-attachment: scroll !important; /* ⭐ 性能优化: 解决卡顿问题 */
    background-position: center center !important;
}

* {
    -webkit-tap-highlight-color: transparent !important;
    user-select: none !important;
    outline: none !important;
}

tarea, [contenteditable] {
    user-select: text !important;
}

/* --- 顶部菜单栏 --- */
.nav-menu-bar, #top-nav, #top-bar {
    background-image: url('https://i.mji.rip/2025/08/25/a9ebaf696bb3d219fb557e5757f5053f.jpeg') !important;
    background-size: cover !important;
    background-position: center !important;
    background-repeat: no-repeat !important;
    background-color: transparent !important;
    border-bottom: 2px dashed #151515 !important; 
    box-shadow: none !important;
    display: flex !important; 
    height: 36px !important; 
    box-sizing: border-box !important;
}
.nav-menu-bar .menu_button, .nav-menu-bar .menu_button:hover, #top-bar > .menu_button {
    background: transparent !important;
    border: none !important;
    box-shadow: none !important;
}

.drawer {
    align-items: flex-start !important;
}

/* --- 侧边栏图标 --- */
.drawer-icon, #leftNavDrawerIcon, #rightNavDrawerIcon {
    opacity: 1 !important;
    margin-top: 1px;
}
.drawer-icon::before, #leftNavDrawerIcon::before, #rightNavDrawerIcon::before { 
    content: ''; display: block; 
    background-size: contain; background-repeat: no-repeat; background-position: center; 
}

#sys-settings-button .drawer-icon::before, #advanced-formatting-button .drawer-icon::before, #WI-SP-button .drawer-icon::before, #user-settings-button .drawer-icon::before, #logo_block .drawer-icon::before, #extensions-settings-button .drawer-icon::before, #persona-management-button .drawer-icon::before {
    height: 28px !important; 
    width: auto; 
}

#rightNavDrawerIcon {
    position: relative;
    right: 8px !important;
}
#rightNavDrawerIcon::before { 
    background-image: url('https://i.mji.rip/2025/08/26/f05e77cadd9d7d3358e95c98988e4cc9.png');
    height: 30px !important; 
    width: 45px; 
}

#leftNavDrawerIcon {
    margin-left: 2px;
}
#leftNavDrawerIcon::before { 
    background-image: url('https://i.mji.rip/2025/08/25/0c11567ba44f94b1d4beb1004407fa32.png'); 
    height: 36px !important; 
    width: 32px; 
}

/* --- 更新图标链接 --- */
#logo_block .drawer-icon::before { background-image: url('https://i.mji.rip/2025/08/25/c73c74659877259b599e0d28926c75dc.png'); }
#sys-settings-button .drawer-icon::before { background-image: url('https://i.mji.rip/2025/08/25/c73c74659877259b599e0d28926c75dc.png'); }
#advanced-formatting-button .drawer-icon::before { background-image: url('https://i.mji.rip/2025/08/25/07450e709e9f0bf78a916e68e665d65b.png'); }
#WI-SP-button .drawer-icon::before { background-image: url('https://i.mji.rip/2025/08/25/c73c74659877259b599e0d28926c75dc.png'); }
#user-settings-button .drawer-icon::before { background-image: url('https://i.mji.rip/2025/08/25/07450e709e9f0bf78a916e68e665d65b.png'); } 
#extensions-settings-button .drawer-icon::before { background-image: url('https://i.mji.rip/2025/08/25/07450e709e9f0bf78a916e68e665d65b.png'); }
#persona-management-button .drawer-icon::before { background-image: url('https://i.mji.rip/2025/08/25/c73c74659877259b599e0d28926c75dc.png'); }
#table_database_settings_button .drawer-icon::before, .table_database_settings_drawer .drawer-icon::before {
    background-image: url('https://i.mji.rip/2025/08/26/96d9baa3f9cfbc1ee9bef95af8a01013.png') !important;
    height: 28px !important;
    width: auto;
}


/* --- 底部输入栏图标 --- */
.fa-bars, #extensionsMenuButton, .fa-paper-plane {
    background-size: contain !important;
    background-position: center !important;
    background-repeat: no-repeat !important;
    opacity: 1 !important;
}
.fa-bars::before, .fa-ellipsis-v::before, .fa-paper-plane::before, #extensionsMenuButton::before { display: none !important; }

.fa-bars { background-image: url('https://i.mji.rip/2025/08/26/96d9baa3f9cfbc1ee9bef95af8a01013.png') !important; height: 35px !important; width: 35px !important; position: relative; top: 2px; }
#extensionsMenuButton { background-image: url('https://i.mji.rip/2025/08/26/0b79e212f63ed6b8f45c67e4c100fc7b.png') !important; height: 35px !important; width: 35px !important; position: relative; top: 2px; }
.fa-paper-plane { background-image: url('https://i.mji.rip/2025/08/25/c73c74659877259b599e0d28926c75dc.png') !important; height: 40px !important; width: 40px !important; }

/* --- 通用按钮样式 --- */
.sub_button, #character-tools .text_buttons_holder .menu_button {
    background-image: url('https://i.mji.rip/2025/08/25/80e54f4906a3bde51b7fa84c393adb1d.jpeg') !important;
    background-position: center !important;
    background-size: cover !important;
    background-repeat: no-repeat !important;
    background-color: transparent !important;
    border: 2px dashed #151515 !important;
    border-radius: 8px !important;
    box-shadow: none !important;
    color: #2e2e2e !important;
    text-shadow: none !important;
    padding: 8px 10px !important;
}
.sub_button > *, #character-tools .text_buttons_holder .menu_button > * {
    color: #2e2e2e !important;
}

/*  修正用户设置页面的特定按钮 */
#user-settings-block .menu_button, #user-settings-block .btn {
    background-image: none !important;
    background-color: #0575c1 !important;
    border: 2px dashed #151515 !important;
    border-radius: 8px !important; 
    color: white !important;
    padding: 5px 10px !important;
    filter: none !important;
}
#user-settings-block .menu_button > *, #user-settings-block .btn > * {
    color: white !important;
}

/* --- 设置页标签页按钮 --- */
.inline-drawer-header, #extensions_settings .inline-drawer-toggle.inline-drawer-header, #extensions_settings2 .inline-drawer-toggle.inline-drawer-header, #user-settings-block h4, .standoutHeader {
    background-color: #f1505c !important;
    background-image: url('https://i.mji.rip/2025/08/26/9d56ebd9eeb9b7b0c16a7c439b8a29fc.png') !important;
    background-repeat: no-repeat !important;
    background-position: right 20% center !important;
    background-size: contain !important;
    border: 2px solid #151515 !important;
    color: #2e2e2e !important;
    text-shadow: none !important;
    border-radius: 16px !important;
    padding: 0.7em 15px !important;
    min-height: 38px;
    display: flex; align-items: center;
    box-sizing: border-box;
}
.inline-drawer-header::before { display: none !important; }
.inline-drawer-toggle.inline-drawer-header::after { color: #2e2e2e !important; }


/* --- 表单与输入框样式 --- */
textarea, .text_pole, .search_field, input[type="text"] {
    background-color: white !important;
    border: 2px dashed #151515 !important;
    border-radius: 8px !important;
    color: #2e2e2e !important;
    padding: 5px 10px !important;
}

/*  全局数字输入框样式 */
input[type="number"] {
    background-image: url('https://i.mji.rip/2025/08/25/80e54f4906a3bde51b7fa84c393adb1d.jpeg') !important;
    background-size: cover !important;
    background-position: center !important;
    border: 2px solid #309add !important;
    border-radius: 8px !important;
    color: #2e2e2e !important;
    font-weight: bold !important;
    text-shadow: none !important;
    padding: 8px 10px !important;
    text-align: center !important;
    filter: none !important;
}

/*  用户设置页下拉菜单样式 */
select, #user-settings-block select {
    appearance: none !important;
    -webkit-appearance: none !important;
    background-color: white !important;
    background-image: url('https://i.mji.rip/2025/08/25/37a0d4dbe282ea419275307892244c70.png') !important;
    background-repeat: no-repeat !important;
    background-position: right 10px bottom !important;
    background-size: auto 90% !important;
    border: 2px dashed #151515 !important;
    border-radius: 8px !important;
    color: #2e2e2e !important;
    padding: 8px 40px 8px 10px !important;
}

/* --- 滑块样式 --- */
input[type="range"] {
    -webkit-appearance: none; appearance: none;
    height: 10px !important;
    background: #0575c1 !important;
    border: 2px solid #151515 !important;
    border-radius: 5px !important;
    padding: 0 !important;
    filter: none !important;
    margin-top: 25px !important; 
    box-shadow: none !important;
}
input[type="range"]::-webkit-slider-thumb {
    -webkit-appearance: none; appearance: none; 
    width: 54px !important; 
    height: 54px !important; 
    background: url('https://i.mji.rip/2025/08/25/61d5ce86dfc6f260e2ff9a29e5aa1e6a.png') no-repeat center/contain !important;
    background-color: transparent !important;
    border: none !important; cursor: pointer;
    margin-top: -22px; 
    filter: none !important;
    box-shadow: none !important;
}

/* --- Checkbox 样式 --- */
input[type='checkbox'] {
    -webkit-appearance: none; appearance: none;
    background-color: #0575c1 !important;
    border: 2px solid #151515 !important;
    border-radius: 4px;
    width: 16px; height: 16px;
}

/* --- 底部输入框 --- */
#send_form { 
    border-top: 2px dashed #151515 !important; 
    background-color: white !important;
}


/* ======================================================= */
/* =========   聊天界面重构 (固定布局终极版)   ========= */
/* ======================================================= */

/* 消息间距 */
.mes { 
    position: relative !important; 
    overflow: visible !important;
    max-width: 650px;
    margin-left: auto !important;
    margin-right: auto !important;
    margin-top: 25px !important;
}

/* ⭐ 1. 核心：在对话框顶部创建100px的“安全区” ⭐ */
#chat .mes_block {
    position: relative !important;
    background-image: url('https://i.mji.rip/2025/08/30/2706e35f1f251d75ae3bc1b580edad8e.jpeg') !important;
    background-position: top center !important;
    background-repeat: no-repeat !important;
    background-size: 100% auto !important;
    background-color: white !important;
    border: 3px solid #151515 !important;
    border-radius: 22px !important;
    padding: 100px 15px 20px 15px !important; /* 顶部留出100px空间 */
}

/* ⭐ 2. 思维链：让它在安全区下方自然出现 ⭐ */
.mes_reasoning_header {
    position: relative !important;
    background-color: #e13f4c !important;
    border: 2px dashed #151515 !important;
    padding: px 10px !important;
    border-radius: 8px !important;
    color: white !important;
    margin: -10px 0 15px 0 !important; /* 只需和下面的正文隔开一点距离 */
}

/* ⭐ 3. 正文：删除所有复杂的margin，让它自然流动 ⭐ */
.mes .mes_text {
    position: relative !important;
    margin: 0 !important; /* 删除所有复杂的margin-top */
    padding: 0 !important; /* 清空内边距，因为外框已经有padding */
    overflow: visible !important;
    background-color: transparent !important; 
    border: none !important; 
    min-height: 100px;
    color: #151515 !important;
    font-size: 15px !important;
}


/* ⭐ 4. 头像和名字：将它们“钉”在安全区内 ⭐ */
#chat .mes .mesAvatarWrapper {
    position: absolute !important;
    top: 28px !important; /* 定位在100px安全区内 */
    left: 20px !important;
    width: 72px !important; 
    height: 72px !important; 
    z-index: 10 !important;
}
#chat .mes .avatar {
    position: absolute !important;
    width: 55px !important; 
    height: 55px !important; 
    top: 50% !important; /* 在72x72的容器里居中 */
    left: 50% !important; 
    transform: translate(-50%, -50%) !important;
    z-index: 11 !important;
    border: 2px dashed #151515 !important; 
    border-radius: 50% !important; 
    box-sizing: border-box !important; 
}
#chat .mes .avatar img {
    border-radius: 50% !important;
    border: 2px solid white !important; 
    box-shadow: none !important;
}

/* 名字和时间 */
.mes .name_text { 
    position: absolute !important; 
    top: 35px !important; /* 定位在100px安全区内 */
    left: 90px !important; 
    color: white !important; 
    font-weight: bold; 
}
.mes .timestamp { 
    position: absolute !important; 
    top: 55px !important; /* 定位在100px安全区内 */
    left: 90px !important; 
    color: white !important; 
}

/* 5. 楼层数与Token数：也钉在顶部 */
.mes .mesIDDisplay,
.mes .tokenCounterDisplay,
.mes .mes_timer {
    display: inline-block !important;
    position: absolute !important;
    top: -15px !important; /* 定位在100px安全区内 */
    left: 15px !important;
    transform: none !important;
    color: #2e2e2e !important;
    font-size: 14px !important;
    font-weight: bold !important;
    background-color: transparent !important;
    border: none !important;
    padding: 0 5px !important;
    z-index: 50 !important;
    text-shadow: none !important;
    white-space: nowrap;
}
.mes .tokenCounterDisplay {
    left: 50px !important;
    margin-right: 15px !important; 
}
.mes .tokenCounterDisplay::before, .mes .mes_timer::before { 
    content: " / ";
    color: #2e2e2e !important;
}
.mes .mes_timer {
    left: 95px !important;
}

/* 6. 消息图标按钮：也钉在顶部 */
#chat .mes_block .mes_buttons_wrapper {
    position: absolute !important;
    top: 10px !important; 
    right: 15px !important; 
    left: auto !important; /* 改为靠右对齐 */
    transform: none !important; /* 不再需要居中 */
    z-index: 999 !important; 
    display: flex !important;
    gap: 5px !important;
}
.mes_edit_buttons {
    gap: 3px !important;
}
#chat .mes_block .mes_buttons_wrapper > .mes_button {
    background-color: transparent !important;
    border: 1px solid #151515 !important;
    border-radius: 8px !important;
    padding: 0 !important; 
    min-width: 22px !important;
    min-height: 22px !important;
    box-sizing: border-box !important;
    box-shadow: none !important;
    filter: none !important; 
    aspect-ratio: 1 !important; /* 让按钮变方 */
}
#chat .mes_block .mes_buttons_wrapper > .mes_button > .fa, 
#chat .mes_block .mes_buttons_wrapper > .mes_button::before {
    font-size: 11px !important;
    color: #151515 !important;
    text-shadow: none !important;
}

/* 7. 引用(对话)文本 */
.mes_text q {
    display: inline;
    background-color: #4f86c5 !important; 
    color: white !important;
    border-radius: 99px !important; 
    padding: 0px 8px !important; 
    margin: 2px;
    -webkit-box-decoration-break: clone;
    box-decoration-break: clone;
    line-height: 2;
}

/* 右下角贴图 */
#chat .mes_block::after {
    content: '';
    position: absolute;
    bottom: 5px !important; 
    right: 15px !important; 
    width: 40px !important; 
    height: 40px !important; 
    background-image: url('https://i.mji.rip/2025/08/26/aa14e758bcf43ac28e42a3b0a4c037be.png');
    background-size: contain;
    background-repeat: no-repeat;
    z-index: 100;
    pointer-events: none;
}

/* 隐藏问号(生成信息)按钮及其图标 */
.mes_info_button, .mes .icon-svg {
    display: none !important;
}

#user-settings-block .standoutHeader, #app-version-display {
    font-size: 15px !important;
    white-space: nowrap !important;
    line-height: 1 !important;
    padding-top: 5px !important;
    padding-bottom: 5px !important;
    min-height: unset !important;
}
#app-version-display {
    color: #2586c3 !important;
}


/* --- 其他页面按钮修复 --- */
.list-item-controls .menu_button,
.popup .sub_button,
#dialogue_popup .sub_button {
    background-image: none !important;
    background-color: #ebfaff !important;
    border: 2px solid #309add !important;
    color: #309add !important;
    box-sizing: border-box !important;
}

.list-item-controls .menu_button > .fa,
.popup .sub_button,
#dialogue_popup .sub_button {
    color: #309add !important;
    text-shadow: none !important;
}

.popup .sub_button[value='true'],
#dialogue_popup .sub_button[value='true'],
.popup .yes_button,
#dialogue_popup .yes_button,
.menu_button.popup-button-ok,
.redWarningBG { 
    background-image: none !important;
    background-color: #ebfaff !important; 
    border: 2px solid #309add !important; 
    color: #309add !important; 
}
.redWarningBG > .fa { 
    color: #309add !important; 
}
.redOverlayGlow { 
    color: #2e2e2e !important; 
}

#advanced_formatting_block, #advanced_formatting_block * {
    filter: none !important;
    opacity: 1 !important;
}
#advanced_formatting_block textarea,
#advanced_formatting_block input[type='text'],
#advanced_formatting_block input[type='checkbox'] + label,
#advanced_formatting_block .text_pole {
    background-color: #ebfaff !important;
    border: 2px solid #309add !important;
    color: #2586c3 !important;
}
#advanced_formatting_block select {
    background-color: #ffffee !important;
    border: 2px solid #996d49 !important;
    color: #996d49 !important;
}
#advanced_formatting_block .sub_button:not(.list-item-controls .menu_button) {
    background-image: url('https://i.mji.rip/2025/08/20/c6b69e73b9899a3fc778c6695e9db11a.jpeg') !important;
    color: #ffffd9 !important;
}
#advanced_formatting_block .sub_button:not(.list-item-controls .menu_button) > * {
    color: #ffffd9 !important;
}
